input.command:
cd /tmp
# Need sshpass-free password auth. Use a small expect script with the ssh client.
cat > /tmp/sshtest.exp <<'EOF'
set timeout 40
spawn ssh -p 2222 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o PreferredAuthentications=password -o PubkeyAuthentication=no root@localhost "echo SSH_OK; id; hostname; cat /etc/alpine-release"
expect {
  "assword:" { send "password123\r"; exp_continue }
  "SSH_OK" { puts "\n---GOTLOGIN---"; exp_continue }
  eof
}
EOF
expect /tmp/sshtest.exp 2>&1 | tail -20
